    def get_assertions(self):
        """Extract all Assertion elements from the response."""
        assertions = self.root.findall(
            './/saml:Assertion',
            SAML_NAMESPACES
        )
        return assertions

    def validate_assertion_present(self):
        """Validate that at least one assertion is present in the response."""
        assertions = self.get_assertions()
        if not assertions:
            self.errors.append('No SAML Assertion found in the response.')
            return False
        return True

    def validate_conditions(self, assertion):
        """Validate the Conditions element of an assertion (time-based)."""
        conditions = assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is None:
            # No conditions to validate
            return True

        now = datetime.utcnow()

        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
            # Allow 5 minutes of clock skew
            if now < not_before_dt - timedelta(minutes=5):
                self.errors.append(
                    f'Assertion is not yet valid. NotBefore: {not_before}'
                )
                return False

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
            # Allow 5 minutes of clock skew
            if now >= not_on_or_after_dt + timedelta(minutes=5):
                self.errors.append(
                    f'Assertion has expired. NotOnOrAfter: {not_on_or_after}'
                )
                return False

        return True

