        """Validate InResponseTo matches our original AuthnRequest ID."""
        in_response_to = self.root.get('InResponseTo')
        if expected_request_id and in_response_to:
            if in_response_to != expected_request_id:
                self.errors.append(
                    f'InResponseTo mismatch. Expected: {expected_request_id}, '
                    f'Got: {in_response_to}'
                )
